const config = $('Preparar OQL Activos por persona').first().json || $('Config Reporte').first().json || {};
const timezone = config.timezone || 'America/Santiago';
const company = String(config.Company || config.company || 'TecnoComp').trim();
const organization = String(config.itop_organization || 'Minera GoldFields Chile').trim();

const generatedAt = new Date().toLocaleString('es-CL', {
  timeZone: timezone,
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
});

const generatedAtFile = new Date()
  .toISOString()
  .slice(0, 19)
  .replace(/[:T]/g, '-');

function clean(value) {
  if (value === undefined || value === null) return '';
  if (Array.isArray(value)) return value.map(clean).filter(Boolean).join(', ');
  return String(value).trim();
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function csvEscape(value) {
  const text = String(value ?? '').replace(/"/g, '""');
  return `"${text}"`;
}

function getField(obj, names, fallback = '') {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') {
      return obj[name];
    }

    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') {
      return obj.fields[name];
    }
  }

  return fallback;
}

function flattenInput(items) {
  const rows = [];

  for (const item of items) {
    const j = item.json || {};

    if (j.objects && typeof j.objects === 'object') {
      for (const [key, value] of Object.entries(j.objects)) {
        rows.push({
          key,
          ...(value || {}),
          fields: value?.fields || value || {},
        });
      }
      continue;
    }

    if (Array.isArray(j)) {
      rows.push(...j);
      continue;
    }

    rows.push(j);
  }

  return rows;
}

function parseMailList(value) {
  const raw = Array.isArray(value) ? value.join(',') : value;

  return String(raw ?? '')
    .split(/[;,\n|]+/)
    .map(v => v.trim().toLowerCase())
    .filter(Boolean)
    .filter((value, index, arr) => arr.indexOf(value) === index);
}

function fmtDateOnly(value) {
  const raw = clean(value);
  if (!raw) return '-';

  const d = new Date(raw.replace(' ', 'T'));

  if (Number.isNaN(d.getTime())) return raw;

  return d.toLocaleDateString('es-CL', {
    timeZone: timezone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  });
}

function td(value, align = 'left') {
  return `<td align="${align}" style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${value}</td>`;
}

function th(text, align = 'left') {
  return `<th align="${align}" style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:${align}; padding:8px 7px; border-bottom:1px solid #dbe3ec; white-space:nowrap;">${escapeHtml(text)}</th>`;
}

function table(headers, rows, emptyText = 'Sin registros.') {
  const body = rows.length
    ? rows.join('')
    : `<tr><td colspan="${headers.length}" style="padding:12px; font-size:12px; color:#64748b;">${escapeHtml(emptyText)}</td></tr>`;

  return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" class="data-table" style="width:100%; border-collapse:collapse; border:1px solid #dbe3ec; margin-bottom:14px;"><thead><tr>${headers.map(h => th(h)).join('')}</tr></thead><tbody>${body}</tbody></table>`;
}

function contactText(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    return clean(value);
  }

  if (Array.isArray(value)) {
    return value.map(contactText).filter(Boolean).join(', ');
  }

  if (typeof value === 'object') {
    if (value.fields) return contactText(value.fields);

    const preferred = [
      'contact_id_friendlyname',
      'person_id_friendlyname',
      'user_id_friendlyname',
      'friendlyname',
      'name',
      'contact_name',
      'person_name',
      'email',
      'email_address',
      'function',
      'function_friendlyname',
      'title',
    ];

    const parts = [];

    for (const key of preferred) {
      if (clean(value[key])) parts.push(clean(value[key]));
    }

    return [...new Set(parts)].join(' / ');
  }

  return '';
}

function findContactIds(value, collector = new Set()) {
  if (value === undefined || value === null) return collector;

  if (Array.isArray(value)) {
    for (const entry of value) {
      findContactIds(entry, collector);
    }
    return collector;
  }

  if (typeof value === 'object') {
    const id = value.contact_id || value.person_id || value.contactid || value.id;

    if (id !== undefined && id !== null && id !== '') {
      collector.add(String(id));
    }

    if (value.fields) {
      findContactIds(value.fields, collector);
    }

    for (const entry of Object.values(value)) {
      if (entry && typeof entry === 'object') {
        findContactIds(entry, collector);
      }
    }
  }

  return collector;
}

function pcSubtype(fields) {
  const name = clean(getField(fields, ['name', 'friendlyname'], '')).toUpperCase();
  if (/-L(?:\b|$)/.test(name)) return 'Laptop';
  if (/-D(?:\b|$)/.test(name)) return 'Desktop';
  if (/-T(?:\b|$)/.test(name)) return 'Tablet';
  if (/-V(?:\b|$)/.test(name)) return 'Virtual';
  return 'Sin subclasificar';
}

function normalizeCategory(finalclass, fields) {
  const rawClass = clean(finalclass);
  const lowerClass = rawClass.toLowerCase();
  const hints = [
    rawClass,
    getField(fields, [
      'type',
      'type_friendlyname',
      'category',
      'category_friendlyname',
      'model_id_friendlyname',
      'brand_id_friendlyname',
      'name',
      'friendlyname',
      'description',
    ], ''),
  ].join(' ').toLowerCase();

  if (lowerClass === 'pc' || lowerClass === 'pc/laptop' || lowerClass.includes('pc')) return 'PC';
  if (hints.includes('laptop') || hints.includes('notebook')) return 'PC';
  if (hints.includes('desktop') || hints.includes('computer')) return 'PC';

  if (hints.includes('mobilephone') || hints.includes('phone') || hints.includes('telefono') || hints.includes('movil')) return 'Telefono movil';
  if (hints.includes('tablet')) return 'Tablet';
  if (hints.includes('peripheral') || hints.includes('periferico') || hints.includes('monitor') || hints.includes('dock') || hints.includes('keyboard') || hints.includes('mouse')) return 'Perifericos';
  if (hints.includes('printer') || hints.includes('impresora')) return 'Impresoras';

  return rawClass || 'Otros';
}
function categoryWeight(category) {
  const order = {
    'PC': 10,

    'Telefono movil': 20,
    'Tablet': 30,
    'Perifericos': 40,
    'Impresoras': 50,
    'Otros': 90,
  };

  return order[category] || 80;
}

function statusLabel(fields) {
  const raw = clean(getField(fields, [
    'operational_status_friendlyname',
    'operational_status',
    'status_friendlyname',
    'status',
  ], '-'));

  const lower = raw.toLowerCase();

  if (lower.includes('production') || lower.includes('produccion') || lower.includes('productivo')) return 'Productivo';
  if (lower.includes('stock') || lower.includes('inventario')) return 'Inventario';
  if (lower.includes('obsolete') || lower.includes('obsoleto')) return 'Obsoleto';
  if (lower.includes('implementation') || lower.includes('implement')) return 'No productivo';

  return raw || '-';
}
function assetRow(asset) {
  const typeCell = asset.category === 'PC' ? td(escapeHtml(asset.type || 'Sin subclasificar')) : '';
  return `<tr>${td(`<strong>${escapeHtml(asset.name)}</strong>`)}${typeCell}${td(escapeHtml(asset.status))}${td(escapeHtml(asset.location))}${td(escapeHtml(asset.brand))}${td(escapeHtml(asset.model))}${td(escapeHtml(asset.serial))}${td(escapeHtml(asset.assetNumber))}${td(escapeHtml(asset.warrantyEnd))}</tr>`;
}

function userCard(profile, mail, assetCount) {
  const rows = [
    `<tr>${td('<strong>Nombre</strong>')}${td(escapeHtml(profile.name || 'No informado'))}</tr>`,
    `<tr>${td('<strong>Cargo</strong>')}${td(escapeHtml(profile.role || 'No informado'))}</tr>`,
    `<tr>${td('<strong>Mail</strong>')}${td(escapeHtml(profile.email || mail))}</tr>`,
    `<tr>${td('<strong>Activos asociados</strong>')}${td(`<strong>${assetCount}</strong>`)}</tr>`,
  ];

  return `<div style="font-size:14px; font-weight:bold; color:#1e293b; margin:0 0 8px 0;">Ficha del usuario</div>${table(['Campo', 'Valor'], rows, 'Sin ficha de usuario.')}`;
}

function summaryCards(byCategory) {
  const entries = Array.from(byCategory.entries())
    .sort(([a], [b]) => categoryWeight(a) - categoryWeight(b) || a.localeCompare(b, 'es'));

  if (!entries.length) {
    return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #dbe3ec; margin-bottom:14px;"><tr><td style="padding:12px; font-size:12px; color:#64748b;">Sin activos asociados al usuario.</td></tr></table>`;
  }

  const cells = entries.map(([category, list]) => `<td width="33.33%" valign="top" style="padding:0 8px 8px 0;">
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #dbe3ec; background-color:#f8fafc; border-collapse:collapse;">
      <tr><td style="padding:10px 12px;">
        <div style="font-size:11px; line-height:15px; color:#475569; font-weight:bold;">${escapeHtml(category)}</div>
        <div style="font-size:22px; line-height:28px; color:#0f172a; font-weight:bold; margin-top:2px;">${list.length}</div>
      </td></tr>
    </table>
  </td>`);

  const rows = [];
  for (let i = 0; i < cells.length; i += 3) {
    const rowCells = cells.slice(i, i + 3);
    while (rowCells.length < 3) rowCells.push('<td width="33.33%" style="padding:0 8px 8px 0;">&nbsp;</td>');
    rows.push(`<tr>${rowCells.join('')}</tr>`);
  }

  return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:10px; border-collapse:collapse;">${rows.join('')}</table>`;
}

function categoryBlocks(byCategory) {
  return Array.from(byCategory.entries())
    .sort(([a], [b]) => categoryWeight(a) - categoryWeight(b) || a.localeCompare(b, 'es'))
    .map(([category, list]) => {
      const sorted = [...list].sort((a, b) => String(a.name).localeCompare(String(b.name), 'es'));
      const headers = category === 'PC'
        ? ['Activo', 'Tipo', 'Estado', 'Ubicacion', 'Marca', 'Modelo', 'Serie', 'Asset tag', 'Garantia']
        : ['Activo', 'Estado', 'Ubicacion', 'Marca', 'Modelo', 'Serie', 'Asset tag', 'Garantia'];

      return `<div style="font-size:14px; font-weight:bold; color:#1e293b; margin:18px 0 8px 0;">${escapeHtml(category)} <span style="color:#64748b; font-weight:normal;">(${sorted.length})</span></div>${table(headers, sorted.map(assetRow), 'Sin activos en esta categoria.')}`;
    })
    .join('');
}
/**
 * Personas solicitadas.
 * Deben venir desde el nodo "Preparar OQL Activos por persona".
 */const requestedMails = parseMailList(config.user_mails || config.user_mail);
const personProfiles = Array.isArray(config.person_profiles) ? config.person_profiles : [];

const peopleById = new Map();
const peopleByMail = new Map();

for (const person of personProfiles) {
  const normalizedPerson = {
    id: clean(person.id),
    email: clean(person.email).toLowerCase(),
    name: clean(person.name),
    role: clean(person.role),
    org: clean(person.org),
    status: clean(person.status),
  };

  if (normalizedPerson.id) {
    peopleById.set(String(normalizedPerson.id), normalizedPerson);
  }

  if (normalizedPerson.email) {
    peopleByMail.set(normalizedPerson.email, normalizedPerson);
  }
}

/**
 * Activos recuperados desde el nodo iTop - Activos CMDB,
 * idealmente ya filtrados por JOIN/OQL.
 */
const rows = flattenInput($input.all());

const allAssets = rows.map((row) => {
  const f = row.fields || row;

  const contactsRaw = getField(f, ['contacts_list'], []);
  const contactIds = findContactIds(contactsRaw);

  const finalclassRaw = getField(f, ['finalclass', 'class', 'class_friendlyname'], '-');

  return {
    id: getField(f, ['id'], row.key || row._key || ''),
    name: getField(f, ['name', 'friendlyname'], '-'),
    finalclassRaw,
    category: normalizeCategory(finalclassRaw, f),
    type: pcSubtype(f),
    status: statusLabel(f),
    organization: getField(f, ['org_id_friendlyname', 'organization_name', 'org_name'], '-'),
    location: getField(f, ['location_id_friendlyname', 'location_name', 'location_id'], '-'),
    contactsText: contactText(contactsRaw),
    contactIds,
    brand: getField(f, ['brand_id_friendlyname', 'brand'], '-'),
    model: getField(f, ['model_id_friendlyname', 'model'], '-'),
    serial: getField(f, ['serialnumber', 'serial_number'], '-'),
    assetNumber: getField(f, ['asset_number', 'asset_tag'], '-'),
    productionDate: fmtDateOnly(getField(f, ['move2production', 'production_date'], '')),
    purchaseDate: fmtDateOnly(getField(f, ['purchase_date'], '')),
    warrantyEnd: fmtDateOnly(getField(f, ['end_of_warranty'], '')),
    description: getField(f, ['description'], ''),
    rawFields: f,
  };
});

let totalAssets = 0;
let pcLaptopCount = 0;
let mobileCount = 0;
let tabletCount = 0;
let peripheralCount = 0;
let printerCount = 0;
let otherCount = 0;

const allCsvRows = [];
const userBlocks = [];

for (const mail of requestedMails) {
  const person = peopleByMail.get(mail) || {
    id: '',
    email: mail,
    name: '',
    role: '',
    org: '',
    status: '',
  };

  const personName = clean(person.name).toLowerCase();
  const personEmail = clean(person.email || mail).toLowerCase();

  const assets = allAssets
    .filter(asset => {
      const contacts = clean(asset.contactsText).toLowerCase();
      if (person.id && asset.contactIds.has(String(person.id))) return true;
      if (personEmail && contacts.includes(personEmail)) return true;
      if (personName && contacts.includes(personName)) return true;
      return false;
    })
    .sort((a, b) =>
      categoryWeight(a.category) - categoryWeight(b.category) ||
      String(a.name).localeCompare(String(b.name), 'es')
    );

  const profile = {
    name: person.name || '',
    role: person.role || '',
    email: person.email || mail,
    org: person.org || '',
    status: person.status || '',
  };

  const byCategory = new Map();

  for (const asset of assets) {
    if (!byCategory.has(asset.category)) {
      byCategory.set(asset.category, []);
    }

    byCategory.get(asset.category).push(asset);
  }

  const currentPc = assets.filter(a => a.category === 'PC').length;
  const currentMobile = assets.filter(a => a.category === 'Telefono movil').length;
  const currentTablet = assets.filter(a => a.category === 'Tablet').length;
  const currentPeripheral = assets.filter(a => a.category === 'Perifericos').length;
  const currentPrinter = assets.filter(a => a.category === 'Impresoras').length;
  const currentOther = assets.length - currentPc - currentMobile - currentTablet - currentPeripheral - currentPrinter;

  totalAssets += assets.length;
  pcLaptopCount += currentPc;
  mobileCount += currentMobile;
  tabletCount += currentTablet;
  peripheralCount += currentPeripheral;
  printerCount += currentPrinter;
  otherCount += currentOther;

  userBlocks.push(`<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #cbd5e1; margin:0 0 22px 0; border-collapse:collapse;">
    <tr>
      <td style="background-color:#e2e8f0; padding:12px 14px; border-bottom:1px solid #cbd5e1;">
        <div style="font-size:16px; line-height:22px; font-weight:bold; color:#0f172a;">${escapeHtml(profile.name || mail)}</div>
      </td>
    </tr>
    <tr>
      <td style="padding:14px;">
        ${userCard(profile, mail, assets.length)}
        <div style="font-size:14px; font-weight:bold; color:#1e293b; margin:18px 0 8px 0;">Resumen por categoria</div>
        ${summaryCards(byCategory)}
        ${categoryBlocks(byCategory)}
      </td>
    </tr>
  </table>`);

  for (const asset of assets) {
    allCsvRows.push([
      mail,
      profile.name || '',
      profile.role || '',
      profile.status || '',
      profile.org || '',
      person.id || '',
      asset.category,
      asset.name,
      asset.finalclassRaw,
      asset.status,
      asset.location,
      asset.brand,
      asset.model,
      asset.serial,
      asset.assetNumber,
      asset.organization,
      asset.productionDate,
      asset.purchaseDate,
      asset.warrantyEnd,
      asset.contactsText,
    ]);
  }
}

const csvLines = [
  [
    'usuario_mail',
    'usuario_nombre',
    'usuario_cargo',
    'usuario_estado_itop',
    'usuario_organizacion',
    'usuario_itop_id',
    'categoria',
    'activo',
    'clase_itop',
    'estado',
    'ubicacion',
    'marca',
    'modelo',
    'serie',
    'asset_tag',
    'organizacion_activo',
    'fecha_produccion',
    'fecha_compra',
    'garantia',
    'contactos',
  ].map(csvEscape).join(','),
  ...allCsvRows.map(row => row.map(csvEscape).join(',')),
].join('\r\n');

const fileBase = `cmdb_activos_por_usuario_${generatedAtFile}.csv`;
const detailBlocks = userBlocks.join('\n');

const subjectSuffix = requestedMails.length === 1
  ? ` - ${requestedMails[0]}`
  : ` - ${requestedMails.length} usuarios`;

const reportAudience = requestedMails.length === 1
  ? (clean(peopleByMail.get(requestedMails[0])?.name) || requestedMails[0])
  : 'grupo de usuarios consultados';

const reportDescription = requestedMails.length === 1
  ? `Entrega una vista consolidada de los activos asignados a ${reportAudience} en iTop, incluyendo ficha basica del usuario, resumen por categoria, detalle de activos y archivo CSV adjunto para analisis o respaldo.`
  : `Entrega una vista consolidada de los activos asignados al ${reportAudience} en iTop, incluyendo ficha basica por usuario, resumen por categoria, detalle de activos y archivo CSV adjunto para analisis o respaldo.`;

return [
  {
    json: {
      ...config,

      report_title: 'CMDB - Activos asignados por usuario',

      report_description: reportDescription,

      source_label: 'Produccion / iTop',
      generated_at: generatedAt,

      company,
      Company: company,
      itop_organization: organization,

      user_count: String(requestedMails.length),
      resolved_user_count: String(personProfiles.length),

      total_assets: String(totalAssets),
      pc_laptop_count: String(pcLaptopCount),
      mobile_count: String(mobileCount),
      tablet_count: String(tabletCount),
      peripheral_count: String(peripheralCount),
      printer_count: String(printerCount),
      other_count: String(otherCount),

      detail_blocks: detailBlocks,

      email_to: config.email_to,
      email_cc: config.email_cc || '',
      email_bcc: config.email_bcc || '',

      email_subject: `${config.email_subject || 'CMDB - activos asignados por usuario'}${subjectSuffix}`,

      operational_notes: config.operational_notes ||
        'Vista orientada a facilitar la revision de activos asignados y apoyar procesos de control, entrega o devolucion de equipamiento. El consolidado permite identificar rapidamente cobertura por usuario, categoria y respaldo descargable para seguimiento.',

      csv_filename: fileBase,
    },

    binary: {
      csv: {
        data: Buffer.from(csvLines, 'utf8').toString('base64'),
        mimeType: 'text/csv',
        fileName: fileBase,
      },
    },
  },
];

const fs = require('fs');
const path = require('path');

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function readText(filePath) {
  return fs.readFileSync(filePath, 'utf8').replace(/^\uFEFF/, '');
}

function render(template, values) {
  return String(template || '').replace(/{{\s*([\w.]+)\s*}}/g, (_, key) => {
    const parts = key.split('.');
    let value = values;
    for (const part of parts) value = value?.[part];
    return value === undefined || value === null ? '' : String(value);
  });
}

function normalizeText(value, forSubject = false) {
  let text = String(value ?? '');

  const fixes = [
    ['\u00c3\u0192\u00c2\u00a1', '&aacute;'], ['\u00c3\u00a1', '&aacute;'], ['\u00e1', '&aacute;'],
    ['\u00c3\u0192\u00c2\u00a9', '&eacute;'], ['\u00c3\u00a9', '&eacute;'], ['\u00e9', '&eacute;'],
    ['\u00c3\u0192\u00c2\u00ad', '&iacute;'], ['\u00c3\u00ad', '&iacute;'], ['\u00ed', '&iacute;'],
    ['\u00c3\u0192\u00c2\u00b3', '&oacute;'], ['\u00c3\u00b3', '&oacute;'], ['\u00f3', '&oacute;'],
    ['\u00c3\u0192\u00c2\u00ba', '&uacute;'], ['\u00c3\u00ba', '&uacute;'], ['\u00fa', '&uacute;'],
    ['\u00c3\u0192\u00c2\u00b1', '&ntilde;'], ['\u00c3\u00b1', '&ntilde;'], ['\u00f1', '&ntilde;'],
    ['\u00c3\u0192\u00c2\u00bc', '&uuml;'], ['\u00c3\u00bc', '&uuml;'], ['\u00fc', '&uuml;'],
    ['\u00c3\u0192\u00c2\u0081', '&Aacute;'], ['\u00c3\u0081', '&Aacute;'], ['\u00c1', '&Aacute;'],
    ['\u00c3\u0192\u00c2\u0089', '&Eacute;'], ['\u00c3\u0089', '&Eacute;'], ['\u00c9', '&Eacute;'],
    ['\u00c3\u0192\u00c2\u008d', '&Iacute;'], ['\u00c3\u008d', '&Iacute;'], ['\u00cd', '&Iacute;'],
    ['\u00c3\u0192\u00c2\u0093', '&Oacute;'], ['\u00c3\u0093', '&Oacute;'], ['\u00d3', '&Oacute;'],
    ['\u00c3\u0192\u00c2\u009a', '&Uacute;'], ['\u00c3\u009a', '&Uacute;'], ['\u00da', '&Uacute;'],
    ['\u00c3\u0192\u00c2\u0091', '&Ntilde;'], ['\u00c3\u0091', '&Ntilde;'], ['\u00d1', '&Ntilde;'],
    ['\u00c3\u0192\u00c2\u009c', '&Uuml;'], ['\u00c3\u009c', '&Uuml;'], ['\u00dc', '&Uuml;'],
    ['Telefono movil', 'Tel&eacute;fono m&oacute;vil'],
    ['MOVILES', 'M&Oacute;VILES'],
