function parseMailList(value) {
  return String(value ?? '')
    .split(/[;,\n|]+/)
    .map(v => v.trim().toLowerCase())
    .filter(Boolean)
    .filter((value, index, arr) => arr.indexOf(value) === index);
}

function escapeOql(value) {
  return String(value ?? '').replace(/\\/g, '\\\\').replace(/'/g, "\\'");
}

const userMails = parseMailList(config.user_mails || config.user_mail);

const where = userMails.length
  ? userMails.map(mail => `email = '${escapeOql(mail)}'`).join(' OR ')
  : `email = '__NO_MAIL__'`;

return [
  {
    json: {
      ...config,
      user_mails: userMails,
      person_oql: `SELECT Person WHERE ${where}`,
    },
  },
];

const config = $('Config Reporte').first().json || {};

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function flattenInput(items) {
  const rows = [];

  for (const item of items) {
    const j = item.json || {};

    if (j.objects && typeof j.objects === 'object') {
      for (const [key, value] of Object.entries(j.objects)) {
        rows.push({
          key,
          ...(value || {}),
          fields: value?.fields || value || {},
        });
      }
      continue;
    }

    rows.push(j);
  }

  return rows;
}

function getField(obj, names, fallback = '') {
  for (const name of names) {
    if (obj?.[name] !== undefined && obj[name] !== null && obj[name] !== '') {
      return obj[name];
    }

    if (obj?.fields?.[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') {
      return obj.fields[name];
    }
  }

  return fallback;
}

function escapeOql(value) {
  return String(value ?? '')
    .replace(/\\/g, '\\\\')
    .replace(/'/g, "\\'");
}

const persons = flattenInput($input.all());

const personProfiles = [];
const personIds = [];

for (const row of persons) {
  const f = row.fields || row;

  const id = clean(getField(f, ['id'], row.key || row._key || ''));
  const email = clean(getField(f, ['email'], '')).toLowerCase();
  const friendlyname = clean(getField(f, ['friendlyname'], ''));
  const firstName = clean(getField(f, ['first_name'], ''));
  const lastName = clean(getField(f, ['last_name', 'name'], ''));
  const role = clean(getField(f, ['function', 'function_friendlyname', 'title', 'jobtitle'], ''));

  if (!id) continue;

  personIds.push(id);

  personProfiles.push({
    id,
    email,
    name: friendlyname || [firstName, lastName].filter(Boolean).join(' '),
    role,
    org: clean(getField(f, ['org_id_friendlyname'], '')),
    status: clean(getField(f, ['status'], '')),
  });
}

let assetOql;

if (personIds.length) {
  const whereIds = personIds
    .map(id => `lnk.contact_id = ${escapeOql(id)}`)
    .join(' OR ');

  assetOql = `
SELECT PhysicalDevice AS pd
JOIN lnkContactToFunctionalCI AS lnk ON lnk.functionalci_id = pd.id
WHERE ${whereIds}
`.trim();
} else {
  assetOql = `SELECT PhysicalDevice WHERE id = 0`;
}

return [
  {
    json: {
      ...config,
      person_profiles: personProfiles,
      person_ids: personIds,
      asset_oql: assetOql,
      requested_person_count: personProfiles.length,
    },
  },
];
